export enum CropType {
  WHEAT = 'Wheat',
  RICE = 'Rice',
  TOMATO = 'Tomato',
  POTATO = 'Potato',
  ONION = 'Onion',
  COTTON = 'Cotton',
  MAIZE = 'Maize'
}

export type UserRole = 'farmer' | 'consumer' | null;

export interface UserInput {
  cropType: CropType;
  harvestDate: string;
  quantity: number; // in quintals
  location: string;
}

export interface ConsumerInput {
  location: string;
  preferences: string[];
}

export interface MarketPrice {
  crop: CropType;
  retailPrice: number;
  wholesalePrice: number;
  trend: 'up' | 'down' | 'stable';
  freshnessScore: number;
}

export interface ConsumerPrediction {
  recommendedCrops: MarketPrice[];
  nearbyMarkets: {
    name: string;
    distance: string;
    specialty: string;
    priceRating: 'Cheap' | 'Moderate' | 'Premium';
  }[];
  aiAdvice: string;
}

export interface PriceTrendPoint {
  day: string;
  price: number;
}

export interface SpoilagePoint {
  day: string;
  riskPercentage: number;
}

export interface WeatherData {
  temp: number;
  humidity: number;
  rain_chance: number;
  condition: string;
}

export interface AlternateMarket {
  name: string;
  profit: number;
  distance: string;
}

export interface DailyProfit {
  day: string;
  profit: number;
}

export interface PredictionResult {
  best_day: string;
  best_hour: string;
  best_market: string;
  expected_profit: number;
  spoilage_risk: string;
  spoilage_rate: number;
  route_safety_score: number;
  transport_cost: number;
  confidence: number;
  backup_plan: string;
  weather: WeatherData;
  alternate_market: AlternateMarket;
  profit_forecast: DailyProfit[];
  storage_advice: string;
  ai_reasoning: string;
  price_trend: PriceTrendPoint[];
  spoilage_curve: SpoilagePoint[];
  risk_factors: string[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserInput, PredictionResult, ConsumerInput, ConsumerPrediction, CropType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const predictionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    best_day: { type: Type.STRING },
    best_hour: { type: Type.STRING },
    best_market: { type: Type.STRING },
    expected_profit: { type: Type.NUMBER },
    spoilage_risk: { type: Type.STRING },
    spoilage_rate: { type: Type.NUMBER },
    route_safety_score: { type: Type.NUMBER },
    transport_cost: { type: Type.NUMBER },
    confidence: { type: Type.NUMBER },
    backup_plan: { type: Type.STRING },
    ai_reasoning: { type: Type.STRING },
    storage_advice: { type: Type.STRING },
    weather: {
      type: Type.OBJECT,
      properties: {
        temp: { type: Type.NUMBER },
        humidity: { type: Type.NUMBER },
        rain_chance: { type: Type.NUMBER },
        condition: { type: Type.STRING }
      }
    },
    alternate_market: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        profit: { type: Type.NUMBER },
        distance: { type: Type.STRING }
      }
    },
    profit_forecast: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.STRING },
          profit: { type: Type.NUMBER }
        }
      }
    },
    risk_factors: { type: Type.ARRAY, items: { type: Type.STRING } },
    price_trend: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.STRING },
          price: { type: Type.NUMBER }
        }
      }
    },
    spoilage_curve: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.STRING },
          riskPercentage: { type: Type.NUMBER }
        }
      }
    }
  },
  required: ["best_day", "best_market", "expected_profit", "weather", "ai_reasoning"]
};

const consumerSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    recommendedCrops: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          crop: { type: Type.STRING },
          retailPrice: { type: Type.NUMBER },
          wholesalePrice: { type: Type.NUMBER },
          trend: { type: Type.STRING },
          freshnessScore: { type: Type.NUMBER }
        }
      }
    },
    nearbyMarkets: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          distance: { type: Type.STRING },
          specialty: { type: Type.STRING },
          priceRating: { type: Type.STRING }
        }
      }
    },
    aiAdvice: { type: Type.STRING }
  },
  required: ["recommendedCrops", "nearbyMarkets", "aiAdvice"]
};

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `Act as an Expert Agricultural Logistics AI for Farmers. Location: ${input.location}, Crop: ${input.cropType}. Analyze weather, market prices, and logistics. Return JSON.`;
  return await callGemini(prompt, predictionSchema);
};

export const generateConsumerInsights = async (input: ConsumerInput): Promise<ConsumerPrediction> => {
  const prompt = `Act as a Smart Shopping AI for Consumers. Location: ${input.location}. Analyze nearby market prices and crop freshness. Recommend the best crops to buy today for value and nutrition. Return JSON.`;
  return await callGemini(prompt, consumerSchema);
};

async function callGemini(prompt: string, schema: Schema) {
  const maxRetries = 3;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt,
        config: { responseMimeType: "application/json", responseSchema: schema },
      });
      return JSON.parse(response.text);
    } catch (error) {
      if (attempt === maxRetries) throw error;
      await delay(1000 * Math.pow(2, attempt - 1));
    }
  }
}

import React, { useState } from 'react';
import { generatePrediction, generateConsumerInsights } from './services/geminiService';
import { UserInput, PredictionResult, UserRole, ConsumerPrediction } from './types';
import InputForm from './components/InputForm';
import Dashboard from './components/Dashboard';
import ConsumerDashboard from './components/ConsumerDashboard';
import RoleSelector from './components/RoleSelector';
import { Leaf, Info, MapPin, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(null);
  const [view, setView] = useState<'input' | 'dashboard'>('input');
  const [loading, setLoading] = useState(false);
  const [predictionData, setPredictionData] = useState<PredictionResult | null>(null);
  const [consumerData, setConsumerData] = useState<ConsumerPrediction | null>(null);
  const [lastInput, setLastInput] = useState<UserInput | null>(null);
  const [consumerLocation, setConsumerLocation] = useState('');
  const [error, setError] = useState<string | null>(null);

  const handleFarmerSubmit = async (data: UserInput) => {
    setLoading(true);
    setError(null);
    try {
      const result = await generatePrediction(data);
      setPredictionData(result);
      setLastInput(data);
      setView('dashboard');
    } catch (err: any) {
      setError("Failed to generate prediction. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleConsumerSearch = async (loc: string) => {
    setLoading(true);
    setError(null);
    try {
      const result = await generateConsumerInsights({ location: loc, preferences: [] });
      setConsumerData(result);
      setConsumerLocation(loc);
      setView('dashboard');
    } catch (err: any) {
      setError("Failed to fetch consumer insights. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setView('input');
    setPredictionData(null);
    setConsumerData(null);
    setError(null);
  };

  const handleBackToRoles = () => {
    setRole(null);
    handleReset();
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900">
      {/* Navigation Bar */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center gap-2 cursor-pointer" onClick={handleBackToRoles}>
              <div className={`p-2 rounded-lg ${role === 'consumer' ? 'bg-blue-100' : 'bg-agri-100'}`}>
                <Leaf className={`${role === 'consumer' ? 'text-blue-600' : 'text-agri-600'} w-6 h-6`} />
              </div>
              <div>
                <h1 className="text-xl font-bold text-gray-900 tracking-tight leading-none">AgriConnect</h1>
                <span className={`text-xs font-medium ${role === 'consumer' ? 'text-blue-600' : 'text-agri-600'}`}>
                  {role === 'farmer' ? 'Farmer Logistics' : role === 'consumer' ? 'Smart Shopping' : 'Platform'}
                </span>
              </div>
            </div>
            {role && (
              <div className="flex items-center gap-4">
                <button 
                  onClick={handleBackToRoles}
                  className="text-sm font-medium text-gray-500 hover:text-gray-900 transition-colors"
                >
                  Switch Role
                </button>
                <Info className="text-gray-400" size={20} />
              </div>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-8">
        {error && (
          <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-2">
            <Info size={20} /> {error}
          </div>
        )}

        {!role ? (
          <RoleSelector onSelect={setRole} />
        ) : view === 'input' ? (
          <div className="flex flex-col items-center justify-center py-12">
            {role === 'farmer' ? (
              <InputForm onSubmit={handleFarmerSubmit} isLoading={loading} />
            ) : (
              <div className="w-full max-w-lg bg-white p-8 rounded-3xl shadow-xl border border-blue-100">
                <div className="text-center mb-8">
                   <div className="bg-blue-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4">
                      <MapPin className="text-blue-600 w-8 h-8" />
                   </div>
                   <h2 className="text-2xl font-bold">Find Fresh Produce</h2>
                   <p className="text-gray-500">Enter your location to see market prices.</p>
                </div>
                <div className="space-y-4">
                  <input 
                    type="text" 
                    placeholder="Enter City or Area"
                    className="w-full px-4 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none"
                    value={consumerLocation}
                    onChange={(e) => setConsumerLocation(e.target.value)}
                  />
                  <button 
                    onClick={() => handleConsumerSearch(consumerLocation)}
                    disabled={loading || !consumerLocation}
                    className="w-full py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-700 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
                  >
                    {loading ? <Loader2 className="animate-spin" /> : 'Analyze Markets'}
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          <>
            {role === 'farmer' && predictionData && lastInput && (
              <Dashboard data={predictionData} input={lastInput} onReset={handleReset} />
            )}
            {role === 'consumer' && consumerData && (
              <ConsumerDashboard data={consumerData} location={consumerLocation} onReset={handleReset} />
            )}
          </>
        )}
      </main>

      <footer className="mt-20 border-t border-gray-200 py-10 text-center text-gray-500 text-sm">
        <p>© 2026 AgriConnect Intelligence System. Hack for Social Cause.</p>
      </footer>
    </div>
  );
};

export default App;

