                className="w-full px-4 py-4 bg-white border border-neutral-200 text-sm font-semibold outline-none focus:border-agri-600 transition-colors appearance-none cursor-pointer"
              >
                {Object.values(CropType).map((crop) => (
                  <option key={crop} value={crop}>{crop}</option>
