export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence. 
  Task: Optimize logistics for Farmer at ${input.location}. 
  Crop: ${input.cropType}, Qty: ${input.quantity}, Range: ${input.travelRange}km.
  Analyze MSP (Minimum Safe Price), weather-based spoilage, and shared transport options. 
  Output strict JSON schema.`;

  return await callGemini(prompt, predictionSchema);
};

export const generateConsumerInsights = async (input: { location: string; preferences: string[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: Smart Procurement Hub. 
  Task: Discovery for Consumer at ${input.location}. 
  Calculate MEI (Market Efficiency Index) based on distance, freshness, and price gap transparency.
  Provide 'Smart Basket' optimization across multiple markets. 
  Output strict JSON schema.`;

  return await callGemini(prompt, consumerSchema);
};

async function callGemini(prompt: string, schema: Schema) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: { responseMimeType: "application/json", responseSchema: schema },
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Failure:", error);
    throw error;
  }
}

