export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Strategic Advisor. 
  Persona: ${input.farmerType} Farmer.
  Task: Optimize sales for ${input.quantity} quintals of ${input.cropType} at ${input.location}.
  Context: Harvested on ${input.harvestDate}. Travel limit ${input.travelRange}km.
  Specific Requirements:
  - Calculate MSP (Minimum Safe Price) below which sell is a loss.
  - Detail spoilage decay over 7 days based on current humidity/temp.
  - Evaluate Market Trust Score (payment speed, historical fairness).
  - Identify Transport Pooling opportunities for cost reduction if small farmer.
  - Provide a Backup fallback plan.
  Output JSON.`;

  return await callGemini(prompt, predictionSchema);
};

export const generateConsumerInsights = async (input: { location: string; preferences: string[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: Consumer Procurement Optimization. 
  Location: ${input.location}.
  Task: Identify fresh produce in nearby markets. 
  Metrics:
  - Calculate MEI (Market Efficiency Index) = (Freshness * 0.4) + (PriceSavings * 0.4) - (DistanceImpact * 0.2).
  - Transparency: Show the actual Farmer payout vs Wholesale vs Retail.
  - Optimization: Create a 'Smart Basket' combining multiple markets for max savings.
  Output JSON.`;

  return await callGemini(prompt, consumerSchema);
};

async function callGemini(prompt: string, schema: any) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: schema,
        thinkingConfig: { thinkingBudget: 16384 }
      },
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Critical System Failure:", error);
    throw error;
  }
}

