export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Strategic Advisor. 
  Persona: Farmer.
  Task: Optimize sales strategy for ${input.quantity} ${input.quantityUnit} of ${input.cropType} located in ${input.location}.
  Context:
  - Harvest Time: ${input.harvestDate}.
  - Travel Willingness: Max ${input.travelRange}km.
  - Storage: ${input.storageAvailable ? `${input.storageType} available for ${input.storageDuration}` : 'No storage available'}.

  Constraints to Model:
  1. Perishability Logic: ${input.cropType} has specific decay curves based on harvest time ${input.harvestDate}.
  2. Transport Mapping: Map ${input.quantity} ${input.quantityUnit} to appropriate vehicle size (Mini-truck, Truck, or Tractor).
  3. Distance Sensitivity: Only suggest markets within ${input.travelRange}km unless significantly higher profit exists at the boundary.

  Output Requirements (JSON):
  - Expected Profit: Calculate real market rates.
  - MSP: Minimum Safe Price to break even.
  - Spoilage Curve: 7-day projection of quality loss.
  - Market Trust: History of fairness and payment speed in that region.
  - Backup Strategy: Fallback if best market is congested.`;

  return await callGemini(prompt, predictionSchema);
};

export const generateConsumerInsights = async (input: { location: string; preferences: string[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: Consumer Procurement Hub. 
  Location: ${input.location}.
  Task: Identify fresh produce in nearby markets. 
  Metrics:
  - MEI (Market Efficiency Index) = (Freshness * 0.4) + (PriceSavings * 0.4) - (DistanceImpact * 0.2).
  - Transparency: Show the actual Farmer payout vs Wholesale vs Retail.
  Output JSON.`;

  return await callGemini(prompt, consumerSchema);
};

async function callGemini(prompt: string, schema: any) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: schema,
        thinkingConfig: { thinkingBudget: 16384 }
      },
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Critical System Failure:", error);
    throw error;
  }
}

