         </div>

         <div className="bg-white/5 p-6 border border-white/10 space-y-4">
            <div className="flex items-center gap-2 text-[9px] font-black text-neutral-500 uppercase tracking-widest">
               <AlertTriangle size={14} /> Terrain Risk
            </div>
            <div className="space-y-1">
               <div className="text-xl font-black uppercase tracking-tighter">{data.road_type_risk} RISK</div>
               <p className="text-[10px] font-bold text-neutral-400 uppercase">Traffic Prob: {data.traffic_delay_prob}</p>
            </div>
         </div>
      </div>

      {/* Resilience Indicator */}
      {data.alternate_route_available && (
         <div className="flex items-center gap-4 p-4 bg-blue-900/20 border border-blue-500/20 text-blue-300">
            <Zap size={16} className="text-blue-400 animate-pulse" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em]">Operational Resilience: Alternate Fallback Route Available</span>
         </div>
      )}

      {isHighRisk && (
         <div className="flex items-center gap-4 p-4 bg-red-900/20 border border-red-500/20 text-red-300">
            <AlertTriangle size={16} className="text-red-400" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em]">Caution: Rural roads + Rain buffers applied to transit time</span>
         </div>
      )}
    </div>
  );
};

