export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence. 
  Task: Perform Ground Reality Feasibility Check for ${input.quantity} ${input.quantityUnit} of ${input.cropType}.

  Feasibility Logic (MUST BE WEIGHTED):
  1. Arrival Sync: If Distance/Speed + Traffic Buffer > Selling Window End, REJECT market.
  2. Transit Decay: Model quality loss during transit for ${input.cropType}.
  3. Safety Index: Reduce confidence if route involves rural roads during rain or early morning (night risk).
  4. Resilience: Identify if an alternate fallback route exists.

  Decision Criteria:
  - Reward = (Price * Yield) - (Transport Cost) - (Transit Decay).
  - Risk = Safety Score + Window Delay Risk.

  Output ONE clear actionable market and timing window in JSON format. Ensure arrival_sync_status is based on real-world constraints.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

