export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Trust Layer Enabled.
  Task: Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.

  Trust & Explainability Logic (Part H):
  1. Market Trade-off: Why this market over others? (Distance vs. Price vs. Trust)
  2. Timing Logic: Why today vs tomorrow? (Trend vs Spoilage vs Weather)
  3. Risk Assessment: What specific risks were mitigated?
  4. Delay Impact: What exactly happens to profit/quality if delayed by 24h?

  Explain using simple, authoritative farmer-first language. No technical jargon.

   Decision Criteria:
  - Reward = (Price * Yield) - (Transport Cost) - (Transit Decay) - (Storage Costs).
  - Risk = Safety Score + Window Delay Risk + Spoilage Risk.

  Output ONE clear actionable market, timing, and strategy breakdown in JSON format.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence. 
  Task: Provide market transparency and procurement insights for a consumer in ${input.location}.

  Intelligence Logic:
  1. Price Parity: Compare direct farmer prices vs retail averages in the region.
  2. Quality Mapping: Identify which crops are currently freshest in nearby Mandis.
  3. Optimization: Suggest a "Smart Basket" to minimize cost by choosing specific markets.

  Output regional data in JSON format focusing on transparency and ethical sourcing.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

