export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer (Part L).
  Task: Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.

  Collective Intelligence Logic (Part L):
  1. Community Matching: Scan simulated regional data for other farmers selling ${input.cropType} to nearby mandis in the same time window.
  2. Transport Pooling: Calculate potential cost reduction if transport is shared.
  3. Privacy Guard: Ensure the cooperation_hint is supportive but doesn't reveal names.
  4. Savings Split: Provide a realistic estimate of shared vs solo transport cost.

  Decision Criteria:
  - Include collective_intelligence object.
  - Mention "Privacy First Protocol" in privacy_status.

  Explain using simple, authoritative farmer-first language. No jargon.

  Output JSON format.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Reality Layer (Part Consumer A-B). 
  Task: Provide market transparency and procurement insights for a consumer in ${input.location}.

  Reality-First Discovery Logic:
  1. Location-First: Filter only markets reachable from ${input.location} (within 15km).
  2. Availability Signals: Map active farmer selling plans to show "Available today" (Live supply).
  3. Effective Value Ranking: Rank products by a balance of distance, price, and freshness.
  4. Regional Supply Strength: Score the overall local harvest availability (0-100).

  Output regional data in JSON format focusing on transparency and accessibility.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

