export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Task: Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

