export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Task: Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Strategy Layer (Parts C-F). 
  Location: ${input.location}.

  TASK: Deliver price and market intelligence through the "Rational Buying Layer".

  RULES:
  1. TIMING (PART E): Compare Today vs Tomorrow based on supply inflow. Use calm, forecast-style language.
  2. MARKET COMPARISON (PART F): Synthesize Price, Freshness, and Distance. Select top 1-2 conclusions.
  3. TRAVEL TRADE-OFF: Explicitly nudge against wasteful long trips if savings are minimal (effort awareness).
  4. NO ALARMS: Do not use scarcity or panic language. 

  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

