export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Strategy Layer (Part G & H Optimization). 
  Location: ${input.location}.

  TASK: Implement "Part H: Demand Awareness - Market Balancing Layer".

  RULES FOR PART H (DEMAND AWARENESS):
  1. HIGH DEMAND ALERTS: Identify crops where regional demand is spiking. Message: "High regional demand detected; consider waiting if not urgent to help stabilize prices." (Discourage panic).
  2. SURPLUS NUDGE: Identify crops with high farmer supply and low waste-reduction risk. Message: "Healthy availability today; procurement helps absorb regional farmer surplus and prevent waste." (Encourage absorption).
  3. SEASONAL NUDGE: Identify crops at their peak freshness window. Message: "Seasonal peak arrival; optimal biological freshness and fair regional value." (Align demand with nature).
  4. ADVISORY TONE: Never use sales, FOMO, or scarcity language. Sound like an institutional advisor helping the system stay balanced.

  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

