export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Strategy Layer (Parts J-K). 
  Location: ${input.location}.

  TASK: Generate simple, low-friction signals.

  ALERTS RULES:
  1. PRICE ALERT: Trigger if any staple (Onion/Tomato/Potato) is >15% below regional average. Message: "Good price today near you."
  2. FRESHNESS ALERT: Trigger if any crop has "High" category and <6h transit. Message: "Fresh arrivals today at nearby nodes."
  3. DISTANCE ALERT: Trigger if a market <5km offers similar value to the best node. Message: "Similar value available closer to your position."

  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

