};

export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Strategy Core (Unified Parts G, H, J, K).
  Location: ${input.location}.

  TASK:
  1. SMART BASKET (G): Optimize for the "Weakest-Link" freshness logic and basket-level costing.
  2. DEMAND AWARENESS (H): Nudge for market balancing—warn on high demand (shortage risk) and promote surplus (waste absorption).
  3. ALERTS & UX (J-K): Generate low-friction signals: Price drops, Peak freshness arrivals, and Proximity savings.

  ADVISORY RULES:
  - NO SCARCITY FEAR.
  - NO "LIMITED TIME" OFFERS.
  - SOUND LIKE AN INSTITUTIONAL MARKET ADVISOR.

  Output JSON.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

