export const generatePrediction = async (input: UserInput): Promise<PredictionResult> => {
  const prompt = `System: National Agricultural Intelligence - Collective Intelligence Layer.
  Analyze ${input.quantity} ${input.quantityUnit} of ${input.cropType} at ${input.location}.
  Output JSON. Ensure 'simple_summary' contains no jargon and is useful for a farmer with basic literacy.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: predictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

export const generateConsumerInsights = async (input: { location: string; preferences: any[] }): Promise<ConsumerPrediction> => {
  const prompt = `System: National Agricultural Intelligence - Consumer Strategy Core.
  Location: ${input.location}.
  Output JSON. Ensure 'simple_advice' contains no jargon and is useful for a regular household shopper.`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: consumerPredictionSchema,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
  return JSON.parse(response.text || '{}');
};

